
/* ── Variables ── */
.aquabot-chat[data-v-441e86f1] {
  --blue-1: #1a6bff;
  --blue-2: #00c6ff;
  --blue-3: #e8f1ff;
  --bg: #f4f7fb;
  --surface: #ffffff;
  --border: #e1e8f0;
  --text-1: #0f1923;
  --text-2: #5a6a7a;
  --text-3: #9aaabb;
  --danger: #e5474b;
  --radius: 16px;
  --radius-sm: 8px;
  --shadow: 0 2px 12px rgba(26,107,255,.10);
  --shadow-lg: 0 8px 32px rgba(26,107,255,.15);

  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 500px;
  background: var(--bg);
  font-family: 'DM Sans', 'Nunito', system-ui, sans-serif;
  color: var(--text-1);
  border-radius: var(--radius);
  overflow: hidden;
  box-shadow: var(--shadow-lg);
}

/* ── Header ── */
.chat-header[data-v-441e86f1] {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 18px;
  background: linear-gradient(135deg, var(--blue-1) 0%, #0052cc 100%);
  color: #fff;
  flex-shrink: 0;
}
.header-left[data-v-441e86f1] { display: flex; align-items: center; gap: 12px;
}
.bot-avatar[data-v-441e86f1] { width: 38px; height: 38px; flex-shrink: 0;
}
.bot-avatar svg[data-v-441e86f1] { width: 100%; height: 100%;
}
.header-info[data-v-441e86f1] { display: flex; flex-direction: column; gap: 2px;
}
.bot-name[data-v-441e86f1] { font-size: 15px; font-weight: 700; letter-spacing: .3px;
}
.bot-status[data-v-441e86f1] { font-size: 11.5px; opacity: .85; display: flex; align-items: center; gap: 5px;
}
.status-dot[data-v-441e86f1] {
  width: 7px; height: 7px; border-radius: 50%;
  background: rgba(255,255,255,.4);
  transition: background .3s;
}
.status-dot.active[data-v-441e86f1] { background: #4ade80; box-shadow: 0 0 0 2px rgba(74,222,128,.3);
}
.header-actions[data-v-441e86f1] { display: flex; gap: 6px;
}
.icon-btn[data-v-441e86f1] {
  width: 32px; height: 32px;
  border: none; background: rgba(255,255,255,.15);
  border-radius: 8px; cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  color: #fff; transition: background .2s;
}
.icon-btn[data-v-441e86f1]:hover { background: rgba(255,255,255,.28);
}
.icon-btn svg[data-v-441e86f1] { width: 17px; height: 17px;
}

/* ── Messages ── */
.messages-area[data-v-441e86f1] {
  flex: 1;
  overflow-y: auto;
  padding: 20px 16px 8px;
  scroll-behavior: smooth;
}
.messages-area[data-v-441e86f1]::-webkit-scrollbar { width: 5px;
}
.messages-area[data-v-441e86f1]::-webkit-scrollbar-track { background: transparent;
}
.messages-area[data-v-441e86f1]::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px;
}

/* Welcome */
.welcome-screen[data-v-441e86f1] {
  display: flex; flex-direction: column; align-items: center;
  padding: 36px 20px 16px; text-align: center;
}
.welcome-icon[data-v-441e86f1] { width: 72px; height: 72px; margin-bottom: 16px;
}
.welcome-title[data-v-441e86f1] {
  font-size: 22px; font-weight: 800;
  background: linear-gradient(135deg, var(--blue-1), var(--blue-2));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  margin: 0 0 8px;
}
.welcome-sub[data-v-441e86f1] { color: var(--text-2); font-size: 14px; max-width: 320px; line-height: 1.6; margin: 0 0 20px;
}
.suggestion-chips[data-v-441e86f1] { display: flex; flex-wrap: wrap; gap: 8px; justify-content: center;
}
.chip[data-v-441e86f1] {
  padding: 7px 14px; border: 1.5px solid var(--blue-1);
  background: transparent; color: var(--blue-1);
  border-radius: 20px; font-size: 13px; font-weight: 600;
  cursor: pointer; transition: all .2s;
}
.chip[data-v-441e86f1]:hover { background: var(--blue-1); color: #fff;
}

/* Message rows */
.message-list[data-v-441e86f1] { display: flex; flex-direction: column; gap: 16px;
}
.message-row[data-v-441e86f1] {
  display: flex; align-items: flex-start; gap: 10px;
}
.message-row.user[data-v-441e86f1] { flex-direction: row-reverse;
}
.msg-avatar[data-v-441e86f1] { width: 28px; height: 28px; flex-shrink: 0; margin-top: 2px;
}
.msg-avatar svg[data-v-441e86f1] { width: 100%; height: 100%;
}
.message-content-wrap[data-v-441e86f1] { display: flex; flex-direction: column; gap: 4px; max-width: 80%;
}
.message-row.user .message-content-wrap[data-v-441e86f1] { align-items: flex-end;
}

/* Bubbles */
.bubble[data-v-441e86f1] {
  padding: 11px 15px;
  border-radius: 18px;
  font-size: 14px; line-height: 1.65;
  word-break: break-word;
  position: relative;
}
.bubble.assistant[data-v-441e86f1] {
  background: var(--surface);
  border: 1px solid var(--border);
  border-top-left-radius: 4px;
  box-shadow: 0 1px 4px rgba(0,0,0,.05);
  color: var(--text-1);
}
.bubble.user[data-v-441e86f1] {
  background: linear-gradient(135deg, var(--blue-1), #0052cc);
  color: #fff;
  border-top-right-radius: 4px;
}
.bubble.streaming[data-v-441e86f1] { border-color: var(--blue-2);
}
.bubble.editing[data-v-441e86f1] { padding: 10px; background: #fff; border: 1.5px solid var(--blue-1);
}
.bubble-text[data-v-441e86f1] code {
  background: rgba(26,107,255,.08); color: var(--blue-1);
  padding: 1px 5px; border-radius: 4px; font-size: 12.5px;
  font-family: 'JetBrains Mono', monospace;
}
.bubble-text[data-v-441e86f1] strong { font-weight: 700;
}

/* Cursor blink */
.cursor-blink[data-v-441e86f1] {
  display: inline-block; color: var(--blue-1);
  animation: blink-441e86f1 .7s step-end infinite;
}
@keyframes blink-441e86f1 {
0%,100% { opacity: 1;
}
50% { opacity: 0;
}
}

/* Typing */
.typing-bubble[data-v-441e86f1] {
  padding: 14px 18px !important;
  display: flex; gap: 5px; align-items: center;
}
.dot[data-v-441e86f1] {
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--blue-2);
  animation: bounce-441e86f1 1.2s infinite ease-in-out;
}
.dot[data-v-441e86f1]:nth-child(2) { animation-delay: .2s;
}
.dot[data-v-441e86f1]:nth-child(3) { animation-delay: .4s;
}
@keyframes bounce-441e86f1 {
0%,80%,100% { transform: translateY(0);
}
40% { transform: translateY(-6px);
}
}

/* Sources */
.sources-row[data-v-441e86f1] { display: flex; align-items: center; gap: 6px; flex-wrap: wrap; padding: 0 2px;
}
.sources-label[data-v-441e86f1] { font-size: 11px; color: var(--text-3); font-weight: 600;
}
.source-tag[data-v-441e86f1] {
  padding: 2px 8px; background: var(--blue-3);
  color: var(--blue-1); border-radius: 10px; font-size: 11px; font-weight: 600;
}

/* Meta + Actions */
.msg-meta[data-v-441e86f1] {
  display: flex; align-items: center; gap: 10px;
  padding: 0 2px;
}
.timestamp[data-v-441e86f1] { font-size: 11px; color: var(--text-3);
}
.msg-actions[data-v-441e86f1] { display: flex; gap: 4px; opacity: 0; transition: opacity .2s;
}
.message-row:hover .msg-actions[data-v-441e86f1] { opacity: 1;
}
.meta-btn[data-v-441e86f1] {
  display: flex; align-items: center; gap: 3px;
  padding: 3px 7px; border: 1px solid var(--border);
  background: var(--surface); border-radius: 6px;
  font-size: 11.5px; color: var(--text-2); cursor: pointer;
  transition: all .15s;
}
.meta-btn svg[data-v-441e86f1] { width: 12px; height: 12px;
}
.meta-btn[data-v-441e86f1]:hover { background: var(--blue-3); border-color: var(--blue-1); color: var(--blue-1);
}
.meta-btn.danger[data-v-441e86f1]:hover { background: #fff0f0; border-color: var(--danger); color: var(--danger);
}

/* Edit */
.edit-textarea[data-v-441e86f1] {
  width: 100%; min-width: 240px;
  border: none; outline: none; resize: none;
  background: transparent; font: inherit; color: var(--text-1);
  font-size: 14px; line-height: 1.5;
}
.edit-actions[data-v-441e86f1] { display: flex; gap: 8px; margin-top: 8px; justify-content: flex-end;
}
.edit-btn[data-v-441e86f1] {
  padding: 5px 14px; border-radius: 8px; border: none;
  font-size: 12.5px; font-weight: 600; cursor: pointer; transition: all .15s;
}
.edit-btn.save[data-v-441e86f1] { background: var(--blue-1); color: #fff;
}
.edit-btn.save[data-v-441e86f1]:hover { background: #0052cc;
}
.edit-btn.cancel[data-v-441e86f1] { background: var(--border); color: var(--text-2);
}
.edit-btn.cancel[data-v-441e86f1]:hover { background: #d0d8e4;
}

/* ── Input Area ── */
.input-area[data-v-441e86f1] {
  padding: 10px 14px 12px;
  background: var(--surface);
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}
.input-wrap[data-v-441e86f1] {
  display: flex; align-items: flex-end; gap: 8px;
  background: var(--bg);
  border: 1.5px solid var(--border);
  border-radius: 14px;
  padding: 8px 8px 8px 14px;
  transition: border-color .2s, box-shadow .2s;
}
.input-wrap.focused[data-v-441e86f1] {
  border-color: var(--blue-1);
  box-shadow: 0 0 0 3px rgba(26,107,255,.12);
}
.chat-input[data-v-441e86f1] {
  flex: 1; border: none; outline: none; background: transparent;
  font: inherit; font-size: 14px; color: var(--text-1);
  resize: none; line-height: 1.5; max-height: 140px;
  overflow-y: auto;
}
.chat-input[data-v-441e86f1]::-moz-placeholder { color: var(--text-3);
}
.chat-input[data-v-441e86f1]::placeholder { color: var(--text-3);
}
.chat-input[data-v-441e86f1]:disabled { opacity: .6;
}
.send-btn[data-v-441e86f1] {
  width: 36px; height: 36px; flex-shrink: 0;
  border: none; background: var(--border);
  border-radius: 10px; cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  color: var(--text-3); transition: all .2s;
}
.send-btn.active[data-v-441e86f1] { background: var(--blue-1); color: #fff; box-shadow: 0 2px 8px rgba(26,107,255,.35);
}
.send-btn[data-v-441e86f1]:disabled { cursor: not-allowed;
}
.send-btn svg[data-v-441e86f1] { width: 17px; height: 17px;
}
.spin[data-v-441e86f1] { animation: spin-441e86f1 .9s linear infinite;
}
@keyframes spin-441e86f1 {
to { transform: rotate(360deg);
}
}
.input-hint[data-v-441e86f1] { font-size: 11px; color: var(--text-3); margin: 5px 0 0 2px;
}

/* ── Transitions ── */
.msg-enter-active[data-v-441e86f1] { animation: slideIn-441e86f1 .25s ease;
}
@keyframes slideIn-441e86f1 {
from { opacity: 0; transform: translateY(10px);
}
to   { opacity: 1; transform: translateY(0);
}
}

/* ── Responsive ── */
@media (max-width: 500px) {
.message-content-wrap[data-v-441e86f1] { max-width: 92%;
}
.welcome-title[data-v-441e86f1] { font-size: 18px;
}
.suggestion-chips[data-v-441e86f1] { flex-direction: column; align-items: center;
}
}
