
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;600;700;800&family=Inter:wght@400;500;600&display=swap');

/* ── RESET & BASE ─────────────────────────────────────────────────────────── */
[data-v-771d315e] { box-sizing: border-box; margin: 0; padding: 0;
}
.faq-root[data-v-771d315e] {
  --header-bg: #1A4A6B;
  --header-text: #FFFFFF;
  --nav-bg: #009688;
  --nav-text: #FFFFFF;
  font-family: 'Inter', sans-serif;
  background: #ffffff;
  color: #1a1a2e;
  min-height: 100vh;
}

/* ── HEADER ───────────────────────────────────────────────────────────────── */
.app-header[data-v-771d315e] {
  position: relative;
  z-index: 201;
  background: var(--header-bg);
  border-bottom: 1px solid rgba(0, 0, 0, 0.18);
  padding: 14px 24px;
  box-shadow: 0 3px 14px rgba(0, 0, 0, 0.25);
  transition: background 0.4s ease, border-color 0.4s ease, box-shadow 0.4s ease;
}
.app-header-inner[data-v-771d315e] {
  max-width: 1280px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 16px;
}
.header-logos[data-v-771d315e], .header-logos-right[data-v-771d315e] {
  display: flex;
  align-items: center;
  gap: 16px;
}
.header-logos-right[data-v-771d315e] { justify-content: flex-end;
}
.iirs-logo[data-v-771d315e], .gov-logo[data-v-771d315e] {
  height: 64px;
  width: auto;
  -o-object-fit: contain;
     object-fit: contain;
  transition: transform 0.3s ease, filter 0.3s ease;
}
.iirs-logo[data-v-771d315e]:hover, .gov-logo[data-v-771d315e]:hover { transform: scale(1.05);
}
.gov-logo[data-v-771d315e]  { height: 60px;
}
.header-center[data-v-771d315e] { flex: 1; text-align: center; padding: 0 8px;
}
.header-center h2[data-v-771d315e] {
  font-family: 'Outfit', sans-serif;
  font-size: clamp(1.1rem, 2vw, 1.5rem);
  font-weight: 800;
  color: var(--header-text);
  margin: 0 0 4px;
  text-shadow: 0 1px 3px rgba(0,0,0,0.3);
}
.header-center h3[data-v-771d315e] {
  font-size: clamp(1.0rem, 1.6vw, 1.15rem);
  color: var(--header-text);
  opacity: 0.9;
  font-weight: 500;
  margin: 0 0 2px;
}
.header-center h4[data-v-771d315e] {
  font-size: clamp(0.8rem, 1.3vw, 0.95rem);
  color: var(--header-text);
  opacity: 0.75;
  font-weight: 400;
  margin: 0;
}

/* ── NAV ──────────────────────────────────────────────────────────────────── */
.nav-bar[data-v-771d315e] {
  position: sticky;
  top: 0;
  z-index: 200;
  background: var(--nav-bg);
  border-bottom: 2px solid rgba(0, 0, 0, 0.15);
  box-shadow: 0 3px 10px rgba(0, 0, 0, 0.20);
  transition: background 0.4s ease, border-color 0.4s ease, box-shadow 0.4s ease;
}
.nav-inner[data-v-771d315e] {
  max-width: 1280px;
  height: 64px;
  margin: 0 auto;
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 16px;
}
.nav-links[data-v-771d315e] { display: flex; align-items: center; gap: 8px; flex-wrap: wrap;
}
.nav-link[data-v-771d315e] {
  display: inline-flex;
  align-items: center;
  position: relative;
  padding: 8px 20px;
  border-radius: 6px;
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--nav-text);
  background: none;
  border: none;
  cursor: pointer;
  text-decoration: none;
  font-family: 'Inter', sans-serif;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  transition: all 0.2s ease;
}
.nav-link[data-v-771d315e]::after {
  content: '';
  position: absolute;
  bottom: 4px;
  left: 50%;
  width: 0%;
  height: 2px;
  background: var(--nav-text);
  transition: all 0.3s ease;
  transform: translateX(-50%);
  border-radius: 2px;
}
.nav-link[data-v-771d315e]:hover, .nav-link.active[data-v-771d315e] {
  background: rgba(255,255,255,0.18);
  color: #ffffff;
}
.nav-link[data-v-771d315e]:hover::after, .nav-link.active[data-v-771d315e]::after { width: 70%;
}

/* ── HERO / SEARCH ────────────────────────────────────────────────────────── */
.faq-hero[data-v-771d315e] {
  background: linear-gradient(160deg, #f0fdf9 0%, #e6f4f1 100%);
  border-bottom: 1px solid #d1e9e4;
  text-align: center;
  padding: 60px 24px 48px;
}
.faq-hero-tag[data-v-771d315e] {
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  color: #0d9488;
  text-transform: uppercase;
  margin-bottom: 12px;
}
.faq-hero-title[data-v-771d315e] {
  font-family: 'Outfit', sans-serif;
  font-size: clamp(2rem, 4vw, 3rem);
  font-weight: 800;
  color: #0f172a;
  letter-spacing: -0.02em;
  margin-bottom: 14px;
}
.faq-hero-sub[data-v-771d315e] {
  font-size: 1.05rem;
  color: #475569;
  line-height: 1.7;
  max-width: 560px;
  margin: 0 auto 36px;
}

/* Search bar */
.search-wrap[data-v-771d315e] {
  position: relative;
  max-width: 620px;
  margin: 0 auto;
}
.search-icon[data-v-771d315e] {
  position: absolute;
  left: 18px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 1.1rem;
  pointer-events: none;
}
.search-input[data-v-771d315e] {
  width: 100%;
  padding: 16px 52px 16px 52px;
  border: 2px solid #cbd5e1;
  border-radius: 50px;
  font-size: 1rem;
  font-family: 'Inter', sans-serif;
  background: #ffffff;
  color: #0f172a;
  outline: none;
  box-shadow: 0 4px 16px rgba(0,0,0,0.08);
  transition: border-color 0.2s, box-shadow 0.2s;
}
.search-input[data-v-771d315e]:focus {
  border-color: #0d9488;
  box-shadow: 0 0 0 4px rgba(13,148,136,0.12), 0 4px 16px rgba(0,0,0,0.08);
}
.search-clear[data-v-771d315e] {
  position: absolute;
  right: 18px;
  top: 50%;
  transform: translateY(-50%);
  background: #e2e8f0;
  border: none;
  border-radius: 50%;
  width: 28px;
  height: 28px;
  cursor: pointer;
  font-size: 0.8rem;
  color: #64748b;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s;
}
.search-clear[data-v-771d315e]:hover { background: #cbd5e1;
}
.no-results[data-v-771d315e] {
  margin-top: 20px;
  color: #64748b;
  font-size: 0.95rem;
}
.result-count[data-v-771d315e] {
  margin-top: 16px;
  color: #0d9488;
  font-size: 0.9rem;
  font-weight: 500;
}

/* ── FAQ LIST ─────────────────────────────────────────────────────────────── */
.faq-list-wrap[data-v-771d315e] {
  max-width: 820px;
  margin: 48px auto 64px;
  padding: 0 24px;
}
.faq-card[data-v-771d315e] {
  border: 1px solid #e2e8f0;
  border-radius: 14px;
  margin-bottom: 12px;
  background: #ffffff;
  overflow: hidden;
  box-shadow: 0 1px 4px rgba(0,0,0,0.04);
  transition: box-shadow 0.25s, border-color 0.25s;
}
.faq-card[data-v-771d315e]:hover {
  box-shadow: 0 4px 18px rgba(0,0,0,0.09);
  border-color: #b2d8d4;
}
.faq-card.open[data-v-771d315e] {
  border-color: #0d9488;
  box-shadow: 0 4px 20px rgba(13,148,136,0.12);
}
.faq-question[data-v-771d315e] {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 20px 24px;
  background: none;
  border: none;
  cursor: pointer;
  text-align: left;
  font-family: 'Inter', sans-serif;
}
.faq-q-text[data-v-771d315e] {
  font-size: 1.02rem;
  font-weight: 600;
  color: #0f172a;
  line-height: 1.5;
  flex: 1;
}
.faq-card.open .faq-q-text[data-v-771d315e] { color: #0d9488;
}
.faq-chevron[data-v-771d315e] {
  font-size: 1.4rem;
  font-weight: 300;
  color: #94a3b8;
  line-height: 1;
  flex-shrink: 0;
  transition: color 0.2s;
}
.faq-card.open .faq-chevron[data-v-771d315e] { color: #0d9488;
}

/* Answer */
.faq-answer-wrap[data-v-771d315e] {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.35s ease;
}
.faq-answer-wrap.visible[data-v-771d315e] { max-height: 600px;
}
.faq-answer[data-v-771d315e] {
  padding: 0 24px 22px 24px;
  font-size: 0.97rem;
  line-height: 1.75;
  color: #475569;
  border-top: 1px solid #f1f5f9;
  padding-top: 18px;
}
.faq-answer code[data-v-771d315e] {
  display: inline-block;
  background: #f0fdf9;
  border: 1px solid #d1e9e4;
  border-radius: 8px;
  padding: 8px 16px;
  font-size: 0.9rem;
  color: #0d9488;
  font-family: 'Courier New', monospace;
  margin: 8px 0;
}
.faq-answer strong[data-v-771d315e] { color: #0f172a;
}

/* Highlight mark */
[data-v-771d315e] mark {
  background: #fef08a;
  color: #1a1a2e;
  border-radius: 3px;
  padding: 0 2px;
}

/* Footer note */
.faq-footer-note[data-v-771d315e] {
  text-align: center;
  padding: 28px 24px;
  background: #f0fdf9;
  border: 1px dashed #99d6cf;
  border-radius: 14px;
  margin-top: 40px;
  font-size: 0.97rem;
  color: #334155;
  line-height: 1.6;
}

/* ── SITE FOOTER ──────────────────────────────────────────────────────────── */
.site-footer[data-v-771d315e] {
  background: #0f172a;
  border-top: 1px solid #1e293b;
  padding: 28px 24px;
}
.footer-inner[data-v-771d315e] {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}
.fb-name[data-v-771d315e] {
  font-family: 'Outfit', sans-serif;
  font-size: 1rem;
  font-weight: 700;
  color: #f8fafc;
  margin-bottom: 4px;
}
.fb-sub[data-v-771d315e] {
  font-size: 0.82rem;
  color: #64748b;
}

/* ── RESPONSIVE ───────────────────────────────────────────────────────────── */
@media (max-width: 640px) {
.app-header-inner[data-v-771d315e] { grid-template-columns: 1fr; text-align: center;
}
.header-logos[data-v-771d315e], .header-logos-right[data-v-771d315e] { justify-content: center;
}
.faq-hero[data-v-771d315e] { padding: 40px 16px 32px;
}
.faq-list-wrap[data-v-771d315e] { padding: 0 12px;
}
.faq-question[data-v-771d315e] { padding: 16px;
}
.faq-answer[data-v-771d315e] { padding: 14px 16px 18px;
}
.nav-link[data-v-771d315e] { padding: 8px 12px; font-size: 0.82rem;
}
}
